function generarVersionDificil(nombreOriginal) {
        const testOriginal = baseDeDatosPreguntas[nombreOriginal];
const testDificil = [];

testOriginal.forEach(p => {
    let opcionesClonadas = [...p.opciones];
    let textoCorrecto = opcionesClonadas[p.respuestaCorrecta];

    for (let i = opcionesClonadas.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [opcionesClonadas[i], opcionesClonadas[j]] = [opcionesClonadas[j], opcionesClonadas[i]];
    }

    let nuevoIndiceCorrecto = opcionesClonadas.indexOf(textoCorrecto);

    testDificil.push({
        pregunta: p.pregunta,
        opciones: opcionesClonadas,
        respuestaCorrecta: nuevoIndiceCorrecto
    });
});

return testDificil;
}

